  and m.module_number = 10 and l.lesson_number = 5;

update public.lessons l set enhancements = $ench${"industryStory":"An engineer nearly pasted proprietary code into a public AI tool for help. Catching that habit is essential — responsible AI use (data, verification, accountability) is now expected, and a leak can be career-defining.","visualAid":{"type":"comparison","title":"Responsible AI in automation","headers":["Do","Do not"],"rows":[["Sanitise before pasting","Share secrets or proprietary code"],["Verify specifics against reality","Trust output as fact"],["Run, review and own the code","Commit code you cannot explain"]]},"davidTip":"Before pasting anything, ask \"would I be comfortable if this were public?\" Verify hallucination-prone specifics, and never let AI dependence dull your fundamentals — you must be able to debug what you ship.","miniChallenge":"Write your three personal rules for responsible AI use in automation.","modelAnswer":"## Example\n1) Never paste secrets or proprietary code into public tools. 2) Verify generated specifics (locators, APIs) against the real app. 3) Run and understand every line before committing.","portfolioBuilder":"An \"AI-assisted automation\" note in your capstone — prompts used, what you accepted/changed, your safety rules — shows modern, responsible engineering practice."}$ench$::jsonb
